import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        String userInput;

        try {
            System.out.print("Enter your name: ");
            userInput = reader.readLine();

            // Properly handling user input by encoding it before printing to prevent XSS
            System.out.println("<p>Welcome, " + Encode.forHtml(userInput) + "!</p>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
